    15→// StructField information for each the field in structure
    16→type StructField struct {
    17→	FieldName    string
    18→	RenderName   string
    19→	AnchorName   string
    20→	AliasName    string
    21→	IsAutoAnchor bool
    22→	IsAutoAlias  bool
    23→	IsOmitEmpty  bool
