    82→func isIgnoredStructField(field reflect.StructField) bool {
    83→	if field.PkgPath != "" && !field.Anonymous {
    84→		// private field
    85→		return true
    86→	}
    87→	tag := getTag(field)
    88→	if tag == "-" {
    89→		return true
    90→	}
    91→	return false
    92→}
