   105→func (m StructFieldMap) hasMergeProperty() bool {
   106→	for _, v := range m {
   107→		if v.IsOmitEmpty && v.IsInline && v.IsAutoAlias {
   108→			return true
   109→		}
   110→	}
   111→	return false
   112→}
