cat > /tmp/test_comprehensive.go << 'EOF'
package main

import (
	"fmt"
	"strings"

	"github.com/goccy/go-yaml"
)

type Default struct {
	Key string `yaml:"key"`
}

type Test struct {
	First    string  `yaml:"first"`
	Defaults Default `yaml:"second"`
}

func main() {
	tests := []struct {
		name     string
		yaml     string
		expected string
	}{
		{
			"null node with comments",
			`first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`,
			"My default Value",
		},
		{
			"explicit null value",
			`first: "Test"
second: null
`,
			"My default Value",
		},
		{
			"empty mapping",
			`first: "Test"
second: {}
`,
			"My default Value",
		},
		{
			"with YAML value",
			`first: "Test"
second:
  key: "Value from YAML"
`,
			"Value from YAML",
		},
	}

	for _, tc := range tests {
		test := Test{Defaults: Default{Key: "My default Value"}}
		d := yaml.NewDecoder(strings.NewReader(tc.yaml))
		err := d.Decode(&test)
		if err != nil {
			fmt.Printf("❌ %s: Error - %v\n", tc.name, err)
			continue
		}

		if test.Defaults.Key == tc.expected {
			fmt.Printf("✓ %s: PASSED\n", tc.name)
		} else {
			fmt.Printf("❌ %s: FAILED (got %q, expected %q)\n", tc.name, test.Defaults.Key, tc.expected)
		}
	}
}
EOF
